# Starship Control

class Engine:
    def __init__(self):
        self.fuel = 100
        self.speed = 0

    def throttle(self, pct):
        self.speed = pct
        self.fuel -= pct * 0.1

    def brake(self):
        self.speed = 0

class Shields:
    def __init__(self):
        self.power = 100

    def absorb(self, damage):
        self.power -= damage

    def recharge(self):
        self.power = 100

def launch(ship):
    ship.throttle(50)
    print("Launched!")
